"use client";

import { useEffect, useMemo, useState } from "react";
import { apiFetch } from "@/lib/api";
import Pagination from "@/components/Pagination";
import Drawer from "@/components/Drawer";
import CarForm from "@/components/CarForm";

type CarRow = {
  id: string;
  company: string;
  registration: string;
  brand: string;
  driver: string;
};

type PagedResponse<T> = {
  items: T[];
  total: number;
  page: number;
  per_page: number;
};

export default function CarsPage() {
  const [rows, setRows] = useState<CarRow[]>([]);
  const [total, setTotal] = useState(0);
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState("");
  const [loading, setLoading] = useState(true);
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const perPage = 10;

  function load() {
    setLoading(true);
    apiFetch<PagedResponse<CarRow>>(
      `/api/cars?page=${page}&per_page=${perPage}&search=${encodeURIComponent(search)}`
    )
      .then((data) => {

        console.log("Fetched cars", data);
        setRows(data.items);
        setTotal(data.total);
      })
      .finally(() => setLoading(false));
  }

  useEffect(() => {
    load();
  }, [page, search]);

  const totalPages = useMemo(() => Math.ceil(total / perPage), [total]);

  function openCreate() {
    setEditingId(null);
    setDrawerOpen(true);
  }

  function openEdit(id: string) {
    setEditingId(id);
    setDrawerOpen(true);
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-wrap items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-semibold text-slate-900">ข้อมูลรถ</h1>
          <p className="text-sm text-slate-500">จัดการข้อมูลรถทั้งหมด</p>
        </div>
        <button
          onClick={openCreate}
          className="rounded-xl bg-gradient-to-r from-blue-600 to-sky-500 px-4 py-2 text-sm font-semibold text-white shadow-lg shadow-blue-200"
        >
          เพิ่มรายการรถ
        </button>
      </div>

      <div className="rounded-2xl border border-blue-100 bg-white shadow-sm">
        <div className="flex flex-wrap items-center justify-between gap-3 border-b border-blue-50 px-5 py-4">
          <h2 className="text-sm font-semibold text-slate-700">รายการรถ</h2>
          <input
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="ค้นหา..."
            className="w-full max-w-xs rounded-xl border border-blue-100 bg-slate-50 px-3 py-2 text-sm focus:outline-none focus:ring-4 focus:ring-blue-100"
          />
        </div>
        <div className="overflow-x-auto">
          <table className="min-w-full text-sm">
            <thead className="bg-blue-50 text-slate-600">
              <tr>
                <th className="px-5 py-3 text-left font-semibold">No.</th>
                <th className="px-5 py-3 text-left font-semibold">บริษัท</th>
                <th className="px-5 py-3 text-left font-semibold">ทะเบียนรถ</th>
                <th className="px-5 py-3 text-left font-semibold">ยี่ห้อ</th>
                <th className="px-5 py-3 text-left font-semibold">ผขร.</th>
                <th className="px-5 py-3 text-left font-semibold">Actions</th>
              </tr>
            </thead>
            <tbody>
              {loading ? (
                <tr>
                  <td colSpan={6} className="px-5 py-6 text-center text-slate-500">
                    Loading...
                  </td>
                </tr>
              ) : rows.length === 0 ? (
                <tr>
                  <td colSpan={6} className="px-5 py-6 text-center text-slate-500">
                    ไม่พบข้อมูล
                  </td>
                </tr>
              ) : (
                rows.map((row, idx) => (
                  <tr key={row.id} className="border-t border-blue-50">
                    <td className="px-5 py-3">{(page - 1) * perPage + idx + 1}</td>
                    <td className="px-5 py-3">{row.company}</td>
                    <td className="px-5 py-3">{row.registration}</td>
                    <td className="px-5 py-3">{row.brand}</td>
                    <td className="px-5 py-3">{row.driver}</td>
                    <td className="px-5 py-3">
                      <div className="flex gap-2">
                        <button className="rounded-lg bg-blue-100 px-3 py-1 text-xs font-semibold text-blue-700">เชค</button>
                        <button className="rounded-lg bg-slate-100 px-3 py-1 text-xs font-semibold text-slate-600">รายงาน</button>
                        <button
                          onClick={() => openEdit(row.id)}
                          className="rounded-lg bg-slate-100 px-3 py-1 text-xs font-semibold text-slate-600"
                        >
                          ดู/แก้ไข
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
        <div className="border-t border-blue-50 px-5 py-4">
          <Pagination current={page} totalPages={totalPages} onChange={setPage} />
        </div>
      </div>

      <Drawer
        open={drawerOpen}
        title={editingId ? "แก้ไขข้อมูลรถ" : "เพิ่มข้อมูลรถ"}
        onClose={() => setDrawerOpen(false)}
      >
        <CarForm
          carId={editingId}
          onSaved={() => {
            setDrawerOpen(false);
            load();
          }}
        />
      </Drawer>
    </div>
  );
}
